module top_module(in, not_out);input [2:0] in;
    output reg [7:0] not_out; // Changed to reg type

    always @ (in)
        case (in)
            3'b000: not_out = 8'b00000001;
            3'b001: not_out = 8'b00000010;
            3'b010: not_out = 8'b00000100;
            3'b011: not_out = 8'b00001000;
            3'b100: not_out = 8'b00010000;
            3'b101: not_out = 8'b00100000;
            3'b110: not_out = 8'b01000000;
            3'b111: not_out = 8'b10000000;
            default: not_out = 8'b00000000; // Optional: handle default case
        endcase
endmodule
